<?php namespace App\Repositories\Inventory;use App\Repositories\BaseRepository;use App\Models\Inventory\Vendor;use Illuminate\Database\Eloquent\Collection;class VendorRepository extends BaseRepository{    public function __construct(Vendor $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByName(string $name): ?Vendor    {        return $this->query()->where('name', $name)->first();    }    public function findByCode(string $code): ?Vendor    {        return $this->query()->where('code', $code)->first();    }    public function findByEmail(string $email): ?Vendor    {        return $this->query()->where('email', $email)->first();    }    public function findByPhone(string $phone): Collection    {        return $this->findByField('phone', $phone);    }    public function getActiveVendors(): Collection    {        return $this->query()->where('is_active', true)->get();    }    public function getByCategory(string $category): Collection    {        return $this->findByField('category', $category);    }    public function searchVendors(string $keyword): Collection    {        return $this->query()->where('name', 'like', "%{$keyword}%")->orWhere('code', 'like', "%{$keyword}%")->orWhere('email', 'like', "%{$keyword}%")->orWhere('phone', 'like', "%{$keyword}%")->orWhere('contact_person', 'like', "%{$keyword}%")->get();    }    public function getByRating(int $minRating): Collection    {        return $this->query()->where('rating', '>=', $minRating)->get();    }    public function getVendorWithOrders(int $vendorId): ?Vendor    {        return $this->query()->with('purchaseOrders')->findOrFail($vendorId);    }}